// src/pages/FarmDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
import speciesData from '../data/speciesData';

function FarmDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farm, setFarm] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // State chính cho form, chứa dữ liệu cuối cùng sẽ được gửi đi
  const [activityFormData, setActivityFormData] = useState({
    speciesName: '',
    scientificName: '',
    date: '',
    increase: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    decrease: { parents: { male: 0, female: 0 }, otherIndividuals: { male: 0, female: 0, unidentified: 0 } },
    reasonForChange: '',
  });

  // State riêng để điều khiển giao diện
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  const fetchFarmDetails = useCallback(async () => { /* ... giữ nguyên ... */ }, [farmId, token, navigate]);
  useEffect(() => { fetchFarmDetails(); }, [fetchFarmDetails]);

  // Hàm xử lý cho các ô input thông thường (bao gồm cả ô nhập tay)
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    let newFormData = { ...activityFormData };

    if (['speciesName', 'scientificName', 'date', 'reasonForChange'].includes(name)) {
      newFormData[name] = value;
    } else {
      const [mainField, subField, prop] = name.split('.');
      newFormData = {
        ...newFormData,
        [mainField]: { ...newFormData[mainField], [subField]: { ...newFormData[mainField][subField], [prop]: parseInt(value, 10) || 0 } },
      };
    }
    setActivityFormData(newFormData);
  };

  // Hàm xử lý riêng cho dropdown chọn loài (để chuyển đổi chế độ)
  const handleSpeciesModeChange = (e) => {
    const value = e.target.value;
    setSelectedSpecies(value);

    if (value === 'manual' || value === 'Nhập thủ công') {
      setIsManualEntry(true);
      // Xóa dữ liệu loài khi chuyển sang nhập tay
      setActivityFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const allSpecies = [...(farm?.loaiDongVatRung || []), ...speciesData];
      const matched = allSpecies.find(s => s.tenLamSan === value);
      // Tự động điền dữ liệu khi chọn từ danh sách
      setActivityFormData(prev => ({
        ...prev,
        speciesName: value,
        scientificName: matched ? matched.tenKhoaHoc : ''
      }));
    }
  };

  const handleAddActivity = async (e) => { /* ... giữ nguyên ... */ };
  const handleDeleteActivity = async (activityId) => { /* ... giữ nguyên ... */ };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;
  if (error) return <div className="form-container"><p style={{ color: 'red' }}>Lỗi: {error}</p></div>;
  if (!farm) return <div className="form-container"><p>Không tìm thấy thông tin.</p></div>;

  return (
    <div className="form-container">
      <style>{/* ... style của bạn ... */}</style>
      <h2>👁️ Logbook: {farm.tenCoSo}</h2>
      
      <div className="form-grid">
        <div className="detail-group"><strong>Farm Name:</strong> <p>{farm.tenCoSo}</p></div>
        <div className="detail-group"><strong>Address:</strong> <p>{farm.diaChiCoSo}</p></div>
      </div>
      
      <h3>Add New Tracking Record:</h3>
      {message && <div className="success-message">{message}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          
          <div className="form-group-full-width">
            <div className="form-grid">
              <div className="form-group">
                <label>Species Name:</label>
                <select
                  value={selectedSpecies}
                  onChange={handleSpeciesModeChange} // <-- Sử dụng hàm xử lý riêng
                  required
                >
                  <option value="">-- Chọn hoặc nhập thủ công --</option>
                  <optgroup label="Loài đã có tại cơ sở">
                    {farm.loaiDongVatRung && farm.loaiDongVatRung.map((species, index) => (
                      <option key={`farm-${index}`} value={species.tenLamSan}>{species.tenLamSan}</option>
                    ))}
                  </optgroup>
                  <optgroup label="Gợi ý các loài khác">
                    {speciesData.map((species, index) => (
                      <option key={`data-${index}`} value={species.tenLamSan}>{species.tenLamSan}</option>
                    ))}
                  </optgroup>
                </select>
              </div>

              {/* Hiển thị tên khoa học tự động điền */}
              {!isManualEntry && activityFormData.speciesName && (
                <div className="form-group">
                  <label>Tên khoa học:</label>
                  <input type="text" value={activityFormData.scientificName} readOnly disabled />
                </div>
              )}
            </div>
          </div>
          
          {/* Khu vực nhập tay chỉ hiện khi cần */}
          {isManualEntry && (
            <div className="form-grid manual-entry-box" style={{ gridColumn: '1 / -1' }}>
              <div className="form-group">
                <label>Tên loài (nhập tay):</label>
                <input
                  type="text"
                  name="speciesName" // <-- Tên này sẽ được handleFormChange xử lý
                  value={activityFormData.speciesName}
                  onChange={handleFormChange}
                  placeholder="Nhập tên loài mới..."
                  required
                />
              </div>
              <div className="form-group">
                <label>Tên khoa học (nhập tay):</label>
                <input
                  type="text"
                  name="scientificName" // <-- Tên này sẽ được handleFormChange xử lý
                  value={activityFormData.scientificName}
                  onChange={handleFormChange}
                  placeholder="Nhập tên khoa học..."
                />
              </div>
            </div>
          )}

          {/* Các trường còn lại của form */}
          <div className="form-group">
            <label>Date Recorded:</label>
            <input type="date" name="date" value={activityFormData.date} onChange={handleFormChange} required />
          </div>
          <div className="form-group">
            <label>Reason for Change:</label>
            <input type="text" name="reasonForChange" value={activityFormData.reasonForChange} onChange={handleFormChange} />
          </div>
        </div>

        {/* ... Phần Increase / Decrease giữ nguyên ... */}
        
        <button type="submit" className="submit-button">Add Record</button>
      </form>

      <h3>Tracking History:</h3>
      {/* ... Bảng hiển thị giữ nguyên ... */}
    </div>
  );
}

export default FarmDetail;
